async (params, browser) => {
  // Search store for products
  await browser.open(`${params.store_url}/search`)

  // Wait for search results to load
  await browser.waitForSelector('body', 15000)

  // Let search results render
  await browser.wait(2500)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const productCards = document.querySelectorAll('.product-card, .grid__item .card, .product-item, [class*="ProductCard"], [class*="product-card"], .search-result, .predictive-search__result-group .predictive-search__item'); for (let i = 0; i < Math.min(productCards.length, 15); i++) { const card = productCards[i]; const nameEl = card.querySelector('a h3, a h2, .card__heading a, .product-card__title, .product-item__title, h3 a, h2 a, .card__text a, .predictive-search__item-heading'); const priceEl = card.querySelector('.price-item, .product-card__price, .product-item__price, .price .money, [class*="price"] span'); const imgEl = card.querySelector('img'); const linkEl = card.querySelector('a[href*="/products/"]'); const compareEl = card.querySelector('.price-item--sale, s .money, .price--compare'); results.push({ name: nameEl ? nameEl.textContent.trim() : '', price: priceEl ? priceEl.textContent.trim() : '', compare_at_price: compareEl ? compareEl.textContent.trim() : '', image: imgEl ? (imgEl.src || imgEl.dataset.src || '') : '', url: linkEl ? linkEl.href : '' }); } if (results.length === 0) { const links = document.querySelectorAll('a[href*="/products/"]'); const seen = new Set(); links.forEach(function(a) { const href = a.href; if (seen.has(href)) return; seen.add(href); const text = a.textContent.trim(); if (text && text.length > 2 && text.length < 200) { results.push({ name: text, price: '', compare_at_price: '', image: '', url: href }); } }); } return { query: '' + params.query + '', result_count: results.length, results: results.slice(0, 15), url: window.location.href }`)

  return search_results
}
